import type { Notification } from '~/types'

export function useNotificationsApi() {
    const { $api } = useNuxtApp()

    return {
        findAll(params?: { page?: number; limit?: number }) {
            return $api<any>('/notifications', { params })
        },
        markAsRead(id: string) {
            return $api<any>(`/notifications/${id}/read`, { method: 'PATCH' })
        },
        markAllAsRead() {
            return $api<any>('/notifications/read-all', { method: 'PATCH' })
        },
        getUnreadCount() {
            return $api<{ count: number }>('/notifications/unread-count')
        },
    }
}
<template>
  <div>
    <definePageMeta :layout="'dashboard'" />
    <div class="mb-6"><h1 class="text-2xl font-bold text-white">Notifications</h1></div>
    <div class="space-y-3 max-w-2xl">
      <div v-if="notifications.length === 0" class="text-center py-12 text-dark-400">No notifications</div>
      <div v-for="n in notifications" :key="n._id" :class="['card-hover cursor-pointer', n.isRead ? 'opacity-60' : '']" @click="markRead(n)">
        <div class="flex items-start gap-3">
          <div :class="['w-2 h-2 rounded-full mt-2 flex-shrink-0', n.isRead ? 'bg-dark-600' : 'bg-primary-500']"></div>
          <div>
            <p class="text-sm font-medium text-white">{{ n.title }}</p>
            <p class="text-sm text-dark-400 mt-0.5">{{ n.message }}</p>
            <p class="text-xs text-dark-500 mt-1">{{ new Date(n.createdAt).toLocaleString() }}</p>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import type { Notification } from '~/types'
definePageMeta({ layout: 'dashboard' })
const api = useNotificationsApi(); const toast = useToast()
const notifications = ref<Notification[]>([])

async function fetch() { try { const r = await api.findAll({ page: 1, limit: 50 }); notifications.value = (r as any)?.data || [] } catch {} }
async function markRead(n: Notification) { if (n.isRead) return; try { await api.markAsRead(n._id); n.isRead = true } catch {} }
onMounted(fetch)
</script>
